-}
+package github.chains;
+
+import com.github.javaparser.StaticJavaParser;
+import com.github.javaparser.ast.CompilationUnit;
+import com.github.javaparser.ast.ImportDeclaration;
+import com.github.javaparser.ast.expr.Name;
+import com.github.javaparser.ast.type.ClassOrInterfaceType;
+
+import java.io.IOException;
+import java.nio.charset.StandardCharsets;
+import java.nio.file.Files;
+import java.nio.file.Path;
+import java.nio.file.Paths;
+import java.util.List;
+
+public class Main {
+    private static final String OLD_PREFIX = "javax.jws";
+    private static final String NEW_PREFIX = "jakarta.jws";
+
+    public static void main(String[] args) throws IOException {
+        if (args.length != 1) {
+            throw new IllegalArgumentException("Expected one argument: source root path");
+        }
+
+        Path sourceRoot = Paths.get(args[0]).toAbsolutePath().normalize();
+        if (!Files.isDirectory(sourceRoot)) {
+            throw new IllegalArgumentException("Source root does not exist or is not a directory: " + sourceRoot);
+        }
+
+        try (var paths = Files.walk(sourceRoot)) {
+            paths.filter(path -> Files.isRegularFile(path) && path.toString().endsWith(".java"))
+                .forEach(Main::rewriteFile);
+        }
+    }
+
+    private static void rewriteFile(Path file) {
+        try {
+            CompilationUnit compilationUnit = StaticJavaParser.parse(file);
+            boolean changed = false;
+
+            for (ImportDeclaration importDeclaration : compilationUnit.getImports()) {
+                String importName = importDeclaration.getNameAsString();
+                if (shouldRewrite(importName)) {
+                    importDeclaration.setName(StaticJavaParser.parseName(rewritePrefix(importName)));
+                    changed = true;
+                }
+            }
+
+            changed |= rewriteNames(compilationUnit.findAll(Name.class));
+            changed |= rewriteTypes(compilationUnit.findAll(ClassOrInterfaceType.class));
+
+            if (changed) {
+                Files.writeString(file, compilationUnit.toString(), StandardCharsets.UTF_8);
+            }
+        } catch (IOException e) {
+            throw new RuntimeException("Failed to rewrite " + file, e);
+        } catch (RuntimeException e) {
+            throw new RuntimeException("Failed to parse " + file, e);
+        }
+    }
+
+    private static boolean rewriteNames(List<Name> names) {
+        boolean changed = false;
+        for (Name name : names) {
+            String current = name.asString();
+            if (shouldRewrite(current)) {
+                name.setIdentifier(rewritePrefix(current));
+                changed = true;
+            }
+        }
+        return changed;
+    }
+
+    private static boolean rewriteTypes(List<ClassOrInterfaceType> types) {
+        boolean changed = false;
+        for (ClassOrInterfaceType type : types) {
+            String current = type.asString();
+            if (shouldRewrite(current)) {
+                type.setName(StaticJavaParser.parseName(rewritePrefix(current)));
+                changed = true;
+            }
+        }
+        return changed;
+    }
+
+    private static boolean shouldRewrite(String name) {
+        return name.equals(OLD_PREFIX) || name.startsWith(OLD_PREFIX + ".");
+    }
+
+    private static String rewritePrefix(String name) {
+        return NEW_PREFIX + name.substring(OLD_PREFIX.length());
+    }
+}
*** End Patch

